SET FOREIGN_KEY_CHECKS = 0;

CREATE TABLE IF NOT EXISTS plans (id INT AUTO_INCREMENT PRIMARY KEY, code VARCHAR(50) NOT NULL UNIQUE, name VARCHAR(100) NOT NULL, monthly_price DECIMAL(10,2) NOT NULL DEFAULT 0.00, description VARCHAR(255) DEFAULT NULL, sort_order INT NOT NULL DEFAULT 0, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS features (id INT AUTO_INCREMENT PRIMARY KEY, feature_key VARCHAR(100) NOT NULL UNIQUE, name VARCHAR(120) NOT NULL, description VARCHAR(255) DEFAULT NULL, sort_order INT NOT NULL DEFAULT 0) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS plan_features (plan_id INT NOT NULL, feature_id INT NOT NULL, enabled TINYINT(1) NOT NULL DEFAULT 1, PRIMARY KEY (plan_id, feature_id), CONSTRAINT fk_plan_features_plan FOREIGN KEY (plan_id) REFERENCES plans(id) ON DELETE CASCADE, CONSTRAINT fk_plan_features_feature FOREIGN KEY (feature_id) REFERENCES features(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS tenants (id INT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(150) NOT NULL, slug VARCHAR(150) NOT NULL UNIQUE, plan_id INT DEFAULT NULL, subscription_status ENUM('trialing','active','past_due','canceled','manual') NOT NULL DEFAULT 'trialing', trial_ends_at DATETIME DEFAULT NULL, stripe_customer_id VARCHAR(100) DEFAULT NULL, stripe_subscription_id VARCHAR(100) DEFAULT NULL, business_email VARCHAR(150) DEFAULT NULL, business_phone VARCHAR(50) DEFAULT NULL, timezone VARCHAR(80) NOT NULL DEFAULT 'America/Chicago', address_line1 VARCHAR(180) DEFAULT NULL, address_line2 VARCHAR(180) DEFAULT NULL, city VARCHAR(120) DEFAULT NULL, state VARCHAR(120) DEFAULT NULL, postal_code VARCHAR(30) DEFAULT NULL, country VARCHAR(80) DEFAULT 'US', onboarding_completed_at DATETIME DEFAULT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT fk_tenants_plan FOREIGN KEY (plan_id) REFERENCES plans(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS tenant_branding (tenant_id INT NOT NULL PRIMARY KEY, logo_path VARCHAR(255) DEFAULT NULL, primary_color VARCHAR(20) NOT NULL DEFAULT '#2563eb', secondary_color VARCHAR(20) NOT NULL DEFAULT '#0f172a', accent_color VARCHAR(20) NOT NULL DEFAULT '#f59e0b', marketing_headline VARCHAR(200) DEFAULT NULL, booking_intro TEXT DEFAULT NULL, footer_text VARCHAR(255) DEFAULT NULL, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT fk_tenant_branding_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS tenant_settings (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT NOT NULL, setting_key VARCHAR(120) NOT NULL, setting_value TEXT DEFAULT NULL, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, UNIQUE KEY uq_tenant_settings (tenant_id, setting_key), CONSTRAINT fk_tenant_settings_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS tenant_features (tenant_id INT NOT NULL, feature_id INT NOT NULL, enabled TINYINT(1) NOT NULL DEFAULT 1, PRIMARY KEY (tenant_id, feature_id), CONSTRAINT fk_tenant_features_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE, CONSTRAINT fk_tenant_features_feature FOREIGN KEY (feature_id) REFERENCES features(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS tenant_payment_accounts (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT NOT NULL, provider VARCHAR(40) NOT NULL DEFAULT 'stripe', stripe_account_id VARCHAR(100) NOT NULL, charges_enabled TINYINT(1) NOT NULL DEFAULT 0, payouts_enabled TINYINT(1) NOT NULL DEFAULT 0, details_submitted TINYINT(1) NOT NULL DEFAULT 0, account_status VARCHAR(40) NOT NULL DEFAULT 'pending', capabilities_json JSON DEFAULT NULL, requirements_json JSON DEFAULT NULL, onboarding_url VARCHAR(500) DEFAULT NULL, last_synced_at DATETIME DEFAULT NULL, disconnected_at DATETIME DEFAULT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, UNIQUE KEY uq_tenant_provider (tenant_id, provider), UNIQUE KEY uq_stripe_account_id (stripe_account_id), CONSTRAINT fk_tenant_payment_accounts_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS users (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT DEFAULT NULL, name VARCHAR(120) NOT NULL, email VARCHAR(150) NOT NULL, password VARCHAR(255) NOT NULL, role VARCHAR(60) NOT NULL DEFAULT 'owner', title VARCHAR(120) DEFAULT NULL, phone VARCHAR(50) DEFAULT NULL, theme_preference ENUM('light','dark') NOT NULL DEFAULT 'dark', active TINYINT(1) NOT NULL DEFAULT 1, must_change_pw TINYINT(1) NOT NULL DEFAULT 0, last_login DATETIME DEFAULT NULL, reset_token VARCHAR(100) DEFAULT NULL, reset_expires_at DATETIME DEFAULT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, deleted_at DATETIME DEFAULT NULL, UNIQUE KEY uq_users_email (email), KEY idx_users_tenant (tenant_id), CONSTRAINT fk_users_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS roles (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT DEFAULT NULL, role_key VARCHAR(80) NOT NULL, name VARCHAR(120) NOT NULL, description VARCHAR(255) DEFAULT NULL, is_system TINYINT(1) NOT NULL DEFAULT 0, is_active TINYINT(1) NOT NULL DEFAULT 1, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, UNIQUE KEY uq_roles_scope (tenant_id, role_key), CONSTRAINT fk_roles_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS permissions (id INT AUTO_INCREMENT PRIMARY KEY, permission_key VARCHAR(120) NOT NULL UNIQUE, area VARCHAR(80) NOT NULL, name VARCHAR(120) NOT NULL, description VARCHAR(255) DEFAULT NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS role_permissions (role_id INT NOT NULL, permission_id INT NOT NULL, allowed TINYINT(1) NOT NULL DEFAULT 1, PRIMARY KEY (role_id, permission_id), CONSTRAINT fk_role_permissions_role FOREIGN KEY (role_id) REFERENCES roles(id) ON DELETE CASCADE, CONSTRAINT fk_role_permissions_permission FOREIGN KEY (permission_id) REFERENCES permissions(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS user_roles (user_id INT NOT NULL, role_id INT NOT NULL, PRIMARY KEY (user_id, role_id), CONSTRAINT fk_user_roles_user FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE, CONSTRAINT fk_user_roles_role FOREIGN KEY (role_id) REFERENCES roles(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS password_resets (id INT AUTO_INCREMENT PRIMARY KEY, user_id INT DEFAULT NULL, email VARCHAR(150) NOT NULL, token VARCHAR(120) NOT NULL UNIQUE, expires_at DATETIME NOT NULL, used_at DATETIME DEFAULT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_password_resets_user FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS onboarding_progress (tenant_id INT NOT NULL PRIMARY KEY, current_step INT NOT NULL DEFAULT 1, completed_steps_json JSON DEFAULT NULL, last_completed_step INT NOT NULL DEFAULT 0, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT fk_onboarding_progress_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS service_categories (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT NOT NULL, name VARCHAR(120) NOT NULL, sort_order INT NOT NULL DEFAULT 0, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_service_categories_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS services (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT NOT NULL, category_id INT DEFAULT NULL, name VARCHAR(150) NOT NULL, description TEXT DEFAULT NULL, price DECIMAL(10,2) NOT NULL DEFAULT 0.00, duration_minutes INT DEFAULT NULL, booking_type VARCHAR(50) NOT NULL DEFAULT 'service', schedule_type VARCHAR(50) NOT NULL DEFAULT 'appointment', deposit_mode ENUM('none','percent','fixed') NOT NULL DEFAULT 'none', deposit_value DECIMAL(10,2) NOT NULL DEFAULT 0.00, is_active TINYINT(1) NOT NULL DEFAULT 1, sort_order INT NOT NULL DEFAULT 0, taxable TINYINT(1) NOT NULL DEFAULT 0, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT fk_services_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE, CONSTRAINT fk_services_category FOREIGN KEY (category_id) REFERENCES service_categories(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS customers (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT NOT NULL, first_name VARCHAR(100) DEFAULT NULL, last_name VARCHAR(100) DEFAULT NULL, company VARCHAR(150) DEFAULT NULL, email VARCHAR(150) DEFAULT NULL, phone VARCHAR(50) DEFAULT NULL, address_line1 VARCHAR(180) DEFAULT NULL, address_line2 VARCHAR(180) DEFAULT NULL, city VARCHAR(120) DEFAULT NULL, state VARCHAR(120) DEFAULT NULL, postal_code VARCHAR(30) DEFAULT NULL, country VARCHAR(80) DEFAULT 'US', notes TEXT DEFAULT NULL, deleted_at DATETIME DEFAULT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, KEY idx_customers_tenant_email (tenant_id, email), KEY idx_customers_tenant_phone (tenant_id, phone), CONSTRAINT fk_customers_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS customer_notes (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT NOT NULL, customer_id INT NOT NULL, user_id INT DEFAULT NULL, note TEXT NOT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_customer_notes_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE, CONSTRAINT fk_customer_notes_customer FOREIGN KEY (customer_id) REFERENCES customers(id) ON DELETE CASCADE, CONSTRAINT fk_customer_notes_user FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS working_hours (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT NOT NULL, weekday TINYINT NOT NULL, start_time TIME DEFAULT NULL, end_time TIME DEFAULT NULL, is_active TINYINT(1) NOT NULL DEFAULT 1, UNIQUE KEY uq_working_hours (tenant_id, weekday), CONSTRAINT fk_working_hours_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS blackout_dates (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT NOT NULL, blackout_date DATE NOT NULL, reason VARCHAR(180) DEFAULT NULL, UNIQUE KEY uq_blackout_dates (tenant_id, blackout_date), CONSTRAINT fk_blackout_dates_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS bookings (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT NOT NULL, booking_number VARCHAR(30) NOT NULL, customer_id INT DEFAULT NULL, status ENUM('requested','confirmed','scheduled','completed','canceled') NOT NULL DEFAULT 'requested', approval_mode ENUM('instant','request') NOT NULL DEFAULT 'request', scheduled_date DATE DEFAULT NULL, start_time TIME DEFAULT NULL, end_time TIME DEFAULT NULL, request_window VARCHAR(120) DEFAULT NULL, notes TEXT DEFAULT NULL, internal_notes TEXT DEFAULT NULL, subtotal DECIMAL(10,2) NOT NULL DEFAULT 0.00, deposit_amount DECIMAL(10,2) NOT NULL DEFAULT 0.00, amount_due DECIMAL(10,2) NOT NULL DEFAULT 0.00, total_amount DECIMAL(10,2) NOT NULL DEFAULT 0.00, currency VARCHAR(10) NOT NULL DEFAULT 'usd', payment_state ENUM('unpaid','deposit_paid','paid','pending','failed','refunded','manual') NOT NULL DEFAULT 'unpaid', payment_option ENUM('deposit','full','manual') NOT NULL DEFAULT 'deposit', source ENUM('public','admin','api') NOT NULL DEFAULT 'public', public_token VARCHAR(100) DEFAULT NULL, assigned_user_id INT DEFAULT NULL, created_by INT DEFAULT NULL, confirmed_at DATETIME DEFAULT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, deleted_at DATETIME DEFAULT NULL, UNIQUE KEY uq_booking_number (booking_number), KEY idx_bookings_tenant_date (tenant_id, scheduled_date), CONSTRAINT fk_bookings_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE, CONSTRAINT fk_bookings_customer FOREIGN KEY (customer_id) REFERENCES customers(id) ON DELETE SET NULL, CONSTRAINT fk_bookings_assigned_user FOREIGN KEY (assigned_user_id) REFERENCES users(id) ON DELETE SET NULL, CONSTRAINT fk_bookings_created_by FOREIGN KEY (created_by) REFERENCES users(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS booking_items (id INT AUTO_INCREMENT PRIMARY KEY, booking_id INT NOT NULL, service_id INT DEFAULT NULL, item_name VARCHAR(180) NOT NULL, quantity DECIMAL(10,2) NOT NULL DEFAULT 1.00, unit_price DECIMAL(10,2) NOT NULL DEFAULT 0.00, amount DECIMAL(10,2) NOT NULL DEFAULT 0.00, duration_minutes INT DEFAULT NULL, deposit_mode ENUM('none','percent','fixed') NOT NULL DEFAULT 'none', deposit_value DECIMAL(10,2) NOT NULL DEFAULT 0.00, CONSTRAINT fk_booking_items_booking FOREIGN KEY (booking_id) REFERENCES bookings(id) ON DELETE CASCADE, CONSTRAINT fk_booking_items_service FOREIGN KEY (service_id) REFERENCES services(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS jobs (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT NOT NULL, booking_id INT DEFAULT NULL, customer_id INT DEFAULT NULL, job_number VARCHAR(30) NOT NULL, title VARCHAR(180) NOT NULL, status ENUM('scheduled','in_progress','waiting','completed','canceled') NOT NULL DEFAULT 'scheduled', scheduled_date DATE DEFAULT NULL, start_time TIME DEFAULT NULL, end_time TIME DEFAULT NULL, assigned_user_id INT DEFAULT NULL, address_line1 VARCHAR(180) DEFAULT NULL, city VARCHAR(120) DEFAULT NULL, state VARCHAR(120) DEFAULT NULL, postal_code VARCHAR(30) DEFAULT NULL, notes TEXT DEFAULT NULL, internal_notes TEXT DEFAULT NULL, completed_at DATETIME DEFAULT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, deleted_at DATETIME DEFAULT NULL, UNIQUE KEY uq_job_number (job_number), CONSTRAINT fk_jobs_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE, CONSTRAINT fk_jobs_booking FOREIGN KEY (booking_id) REFERENCES bookings(id) ON DELETE SET NULL, CONSTRAINT fk_jobs_customer FOREIGN KEY (customer_id) REFERENCES customers(id) ON DELETE SET NULL, CONSTRAINT fk_jobs_assigned_user FOREIGN KEY (assigned_user_id) REFERENCES users(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS job_notes (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT NOT NULL, job_id INT NOT NULL, user_id INT DEFAULT NULL, note TEXT NOT NULL, note_type ENUM('note','status','system') NOT NULL DEFAULT 'note', created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_job_notes_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE, CONSTRAINT fk_job_notes_job FOREIGN KEY (job_id) REFERENCES jobs(id) ON DELETE CASCADE, CONSTRAINT fk_job_notes_user FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS invoices (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT NOT NULL, invoice_number VARCHAR(30) NOT NULL, booking_id INT DEFAULT NULL, customer_id INT DEFAULT NULL, status ENUM('draft','sent','partially_paid','paid','void','canceled') NOT NULL DEFAULT 'draft', subtotal DECIMAL(10,2) NOT NULL DEFAULT 0.00, tax_amount DECIMAL(10,2) NOT NULL DEFAULT 0.00, total DECIMAL(10,2) NOT NULL DEFAULT 0.00, amount_paid DECIMAL(10,2) NOT NULL DEFAULT 0.00, balance_due DECIMAL(10,2) NOT NULL DEFAULT 0.00, due_date DATE DEFAULT NULL, sent_at DATETIME DEFAULT NULL, paid_at DATETIME DEFAULT NULL, notes TEXT DEFAULT NULL, terms TEXT DEFAULT NULL, payment_link_url VARCHAR(500) DEFAULT NULL, created_by INT DEFAULT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, deleted_at DATETIME DEFAULT NULL, UNIQUE KEY uq_invoice_number (invoice_number), CONSTRAINT fk_invoices_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE, CONSTRAINT fk_invoices_booking FOREIGN KEY (booking_id) REFERENCES bookings(id) ON DELETE SET NULL, CONSTRAINT fk_invoices_customer FOREIGN KEY (customer_id) REFERENCES customers(id) ON DELETE SET NULL, CONSTRAINT fk_invoices_created_by FOREIGN KEY (created_by) REFERENCES users(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS invoice_items (id INT AUTO_INCREMENT PRIMARY KEY, invoice_id INT NOT NULL, description VARCHAR(255) NOT NULL, quantity DECIMAL(10,2) NOT NULL DEFAULT 1.00, unit_price DECIMAL(10,2) NOT NULL DEFAULT 0.00, amount DECIMAL(10,2) NOT NULL DEFAULT 0.00, CONSTRAINT fk_invoice_items_invoice FOREIGN KEY (invoice_id) REFERENCES invoices(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS payments (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT NOT NULL, booking_id INT DEFAULT NULL, invoice_id INT DEFAULT NULL, customer_id INT DEFAULT NULL, amount DECIMAL(10,2) NOT NULL DEFAULT 0.00, currency VARCHAR(10) NOT NULL DEFAULT 'usd', payment_method ENUM('stripe','cash','check','bank_transfer','manual') NOT NULL DEFAULT 'stripe', payment_status ENUM('pending','completed','failed','refunded','partial') NOT NULL DEFAULT 'pending', payment_type ENUM('deposit','full','invoice','manual') NOT NULL DEFAULT 'deposit', stripe_checkout_session_id VARCHAR(120) DEFAULT NULL, stripe_payment_intent_id VARCHAR(120) DEFAULT NULL, stripe_charge_id VARCHAR(120) DEFAULT NULL, external_reference VARCHAR(120) DEFAULT NULL, idempotency_key VARCHAR(120) DEFAULT NULL, metadata_json JSON DEFAULT NULL, paid_at DATETIME DEFAULT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, KEY idx_payments_tenant_status (tenant_id, payment_status), CONSTRAINT fk_payments_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE, CONSTRAINT fk_payments_booking FOREIGN KEY (booking_id) REFERENCES bookings(id) ON DELETE SET NULL, CONSTRAINT fk_payments_invoice FOREIGN KEY (invoice_id) REFERENCES invoices(id) ON DELETE SET NULL, CONSTRAINT fk_payments_customer FOREIGN KEY (customer_id) REFERENCES customers(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS payment_event_logs (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT NOT NULL, payment_id INT DEFAULT NULL, event_key VARCHAR(100) NOT NULL, payload_json JSON DEFAULT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_payment_event_logs_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE, CONSTRAINT fk_payment_event_logs_payment FOREIGN KEY (payment_id) REFERENCES payments(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS processed_webhooks (id INT AUTO_INCREMENT PRIMARY KEY, provider VARCHAR(40) NOT NULL, event_id VARCHAR(120) NOT NULL, tenant_id INT DEFAULT NULL, processed_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, UNIQUE KEY uq_processed_webhook (provider, event_id), CONSTRAINT fk_processed_webhooks_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS notification_templates (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT DEFAULT NULL, template_key VARCHAR(80) NOT NULL, channel ENUM('email','sms') NOT NULL DEFAULT 'email', subject_template VARCHAR(255) DEFAULT NULL, body_template TEXT NOT NULL, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, UNIQUE KEY uq_notification_templates (tenant_id, template_key, channel), CONSTRAINT fk_notification_templates_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS notifications (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT NOT NULL, customer_id INT DEFAULT NULL, booking_id INT DEFAULT NULL, invoice_id INT DEFAULT NULL, channel ENUM('email','sms') NOT NULL DEFAULT 'email', template_key VARCHAR(80) DEFAULT NULL, recipient VARCHAR(180) NOT NULL, subject VARCHAR(255) DEFAULT NULL, body TEXT DEFAULT NULL, status ENUM('queued','sent','failed') NOT NULL DEFAULT 'queued', provider VARCHAR(80) DEFAULT NULL, provider_reference VARCHAR(120) DEFAULT NULL, error_message TEXT DEFAULT NULL, sent_at DATETIME DEFAULT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_notifications_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE, CONSTRAINT fk_notifications_customer FOREIGN KEY (customer_id) REFERENCES customers(id) ON DELETE SET NULL, CONSTRAINT fk_notifications_booking FOREIGN KEY (booking_id) REFERENCES bookings(id) ON DELETE SET NULL, CONSTRAINT fk_notifications_invoice FOREIGN KEY (invoice_id) REFERENCES invoices(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS sms_usage_logs (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT NOT NULL, notification_id INT DEFAULT NULL, recipient VARCHAR(180) NOT NULL, segments INT NOT NULL DEFAULT 1, status VARCHAR(50) NOT NULL DEFAULT 'queued', created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_sms_usage_logs_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE, CONSTRAINT fk_sms_usage_logs_notification FOREIGN KEY (notification_id) REFERENCES notifications(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS webhook_endpoints (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT NOT NULL, name VARCHAR(120) NOT NULL, endpoint_url VARCHAR(500) NOT NULL, secret VARCHAR(120) NOT NULL, events_json JSON NOT NULL, is_active TINYINT(1) NOT NULL DEFAULT 1, last_tested_at DATETIME DEFAULT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT fk_webhook_endpoints_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS webhook_deliveries (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT NOT NULL, webhook_endpoint_id INT NOT NULL, event_key VARCHAR(120) NOT NULL, signature VARCHAR(255) DEFAULT NULL, payload_json JSON NOT NULL, response_code INT DEFAULT NULL, response_body TEXT DEFAULT NULL, status ENUM('queued','delivered','failed') NOT NULL DEFAULT 'queued', attempts INT NOT NULL DEFAULT 0, next_attempt_at DATETIME DEFAULT NULL, delivered_at DATETIME DEFAULT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT fk_webhook_deliveries_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE, CONSTRAINT fk_webhook_deliveries_endpoint FOREIGN KEY (webhook_endpoint_id) REFERENCES webhook_endpoints(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS automation_rules (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT NOT NULL, name VARCHAR(120) NOT NULL, trigger_key VARCHAR(100) NOT NULL, conditions_json JSON DEFAULT NULL, actions_json JSON NOT NULL, is_active TINYINT(1) NOT NULL DEFAULT 1, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT fk_automation_rules_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS automation_runs (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT NOT NULL, automation_rule_id INT NOT NULL, trigger_key VARCHAR(100) NOT NULL, entity_type VARCHAR(80) DEFAULT NULL, entity_id INT DEFAULT NULL, scheduled_for DATETIME DEFAULT NULL, status ENUM('queued','running','completed','failed') NOT NULL DEFAULT 'queued', output_json JSON DEFAULT NULL, ran_at DATETIME DEFAULT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_automation_runs_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE, CONSTRAINT fk_automation_runs_rule FOREIGN KEY (automation_rule_id) REFERENCES automation_rules(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS route_groups (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT NOT NULL, route_date DATE NOT NULL, name VARCHAR(150) NOT NULL, created_by INT DEFAULT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_route_groups_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE, CONSTRAINT fk_route_groups_created_by FOREIGN KEY (created_by) REFERENCES users(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS route_stops (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT NOT NULL, route_group_id INT NOT NULL, job_id INT NOT NULL, stop_order INT NOT NULL DEFAULT 1, maps_query VARCHAR(500) DEFAULT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_route_stops_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE, CONSTRAINT fk_route_stops_group FOREIGN KEY (route_group_id) REFERENCES route_groups(id) ON DELETE CASCADE, CONSTRAINT fk_route_stops_job FOREIGN KEY (job_id) REFERENCES jobs(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS exports (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT NOT NULL, export_type VARCHAR(80) NOT NULL, filters_json JSON DEFAULT NULL, file_name VARCHAR(255) DEFAULT NULL, created_by INT DEFAULT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_exports_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE, CONSTRAINT fk_exports_created_by FOREIGN KEY (created_by) REFERENCES users(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS activity_log (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT DEFAULT NULL, user_id INT DEFAULT NULL, action VARCHAR(120) NOT NULL, description TEXT DEFAULT NULL, entity_type VARCHAR(80) DEFAULT NULL, entity_id INT DEFAULT NULL, ip_address VARCHAR(45) DEFAULT NULL, context_json JSON DEFAULT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_activity_log_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE SET NULL, CONSTRAINT fk_activity_log_user FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS error_logs (id INT AUTO_INCREMENT PRIMARY KEY, tenant_id INT DEFAULT NULL, level VARCHAR(40) NOT NULL DEFAULT 'error', message TEXT NOT NULL, context_json JSON DEFAULT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_error_logs_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS two_factor_secrets (user_id INT NOT NULL PRIMARY KEY, secret VARCHAR(64) NOT NULL, enabled TINYINT(1) NOT NULL DEFAULT 0, backup_codes TEXT DEFAULT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT fk_two_factor_secrets_user FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS login_attempts (id INT AUTO_INCREMENT PRIMARY KEY, ip_address VARCHAR(45) NOT NULL, email VARCHAR(180) DEFAULT NULL, attempted_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, KEY idx_login_attempts_ip (ip_address), KEY idx_login_attempts_time (attempted_at)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS rate_limit_locks (ip_address VARCHAR(45) PRIMARY KEY, attempts INT NOT NULL DEFAULT 0, locked_until DATETIME DEFAULT NULL, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

SET FOREIGN_KEY_CHECKS = 1;

INSERT IGNORE INTO plans (id, code, name, monthly_price, description, sort_order) VALUES (1, 'starter', 'Starter', 29.00, 'Booking page, payments, invoicing, dashboard, customer records', 1), (2, 'growth', 'Growth', 59.00, 'Analytics, SMS, reporting, invoice and webhook upgrades', 2), (3, 'pro', 'Pro', 99.00, 'Automations, teams, advanced permissions, branding and route tools', 3);
INSERT IGNORE INTO features (feature_key, name, description, sort_order) VALUES ('booking_page', 'Booking Page', 'Public booking page and booking flow', 1), ('services', 'Services and Products', 'Manage service catalog and pricing', 2), ('payments', 'Payments', 'Stripe and manual payment tracking', 3), ('deposits', 'Deposits', 'Deposit and full payment options', 4), ('invoicing_basic', 'Basic Invoicing', 'Invoices and line items', 5), ('email_notifications', 'Email Notifications', 'Unlimited transactional email notifications', 6), ('dashboard_basic', 'Basic Dashboard', 'Admin dashboard and operational cards', 7), ('customers', 'Customers', 'Customer records and histories', 8), ('jobs', 'Jobs', 'Jobs generated from bookings', 9), ('sms_notifications', 'SMS Notifications', 'One-way SMS notifications', 10), ('analytics_enhanced', 'Enhanced Analytics', 'Improved dashboard and analytics cards', 11), ('invoice_management', 'Enhanced Invoice Management', 'Partial balance and payment management', 12), ('webhooks', 'Outbound Webhooks', 'Register webhook endpoints and deliveries', 13), ('automations', 'Automations', 'Automation rules and scheduled runs', 14), ('team', 'Team Management', 'Multi-user organizations and invites', 15), ('permissions_advanced', 'Advanced Permissions', 'Roles, permissions, scoped visibility', 16), ('branding_advanced', 'Advanced Branding', 'Brand colors, assets, booking page branding', 17), ('route_tools', 'Route Tools', 'Daily route grouping and maps handoff', 18), ('exports', 'Exports', 'CSV accounting exports', 19);
INSERT IGNORE INTO permissions (permission_key, area, name, description) VALUES ('bookings.view', 'bookings', 'View bookings', 'View booking records'), ('bookings.manage', 'bookings', 'Manage bookings', 'Create and update bookings'), ('jobs.view', 'jobs', 'View jobs', 'View jobs and assignments'), ('jobs.manage', 'jobs', 'Manage jobs', 'Create, update and assign jobs'), ('customers.view', 'customers', 'View customers', 'View customer records'), ('customers.manage', 'customers', 'Manage customers', 'Create and update customer records'), ('invoices.view', 'invoices', 'View invoices', 'View invoices'), ('invoices.manage', 'invoices', 'Manage invoices', 'Create, send and edit invoices'), ('payments.view', 'payments', 'View payments', 'View payment records'), ('billing.manage', 'billing', 'Manage billing', 'Manage Stripe Connect and billing setup'), ('settings.manage', 'settings', 'Manage settings', 'Manage tenant settings'), ('team.manage', 'team', 'Manage team', 'Manage users, invites and membership'), ('webhooks.manage', 'webhooks', 'Manage webhooks', 'Manage webhook endpoints'), ('automations.manage', 'automations', 'Manage automations', 'Manage automation rules'), ('analytics.view', 'analytics', 'View analytics', 'View analytics and reporting'), ('branding.manage', 'branding', 'Manage branding', 'Manage logos and colors'), ('exports.view', 'exports', 'Export data', 'Export bookings, invoices and payments');
INSERT IGNORE INTO plan_features (plan_id, feature_id, enabled) SELECT p.id, f.id, 1 FROM plans p INNER JOIN features f ON ((p.code = 'starter' AND f.feature_key IN ('booking_page','services','payments','deposits','invoicing_basic','email_notifications','dashboard_basic','customers','jobs','exports')) OR (p.code = 'growth' AND f.feature_key IN ('booking_page','services','payments','deposits','invoicing_basic','email_notifications','dashboard_basic','customers','jobs','exports','sms_notifications','analytics_enhanced','invoice_management','webhooks')) OR (p.code = 'pro' AND f.feature_key IN ('booking_page','services','payments','deposits','invoicing_basic','email_notifications','dashboard_basic','customers','jobs','exports','sms_notifications','analytics_enhanced','invoice_management','webhooks','automations','team','permissions_advanced','branding_advanced','route_tools')));
